;AACA;AACA;AACA;AACA;AACA;AACA;;AAEA;AACA,IAAI,KAAU,GAAG;AACjB;AACA;AACA;AACA;AACA;AACA;AACA,GAAG;AACH;AACA;AACA;AACA;AACA,GAAG;AACH,CAAC;;AAED","file":"133.js","sourcesContent":["<template>\r\n    <el-dialog\r\n        :title=\"titleDialog\"\r\n        :visible=\"showDialog\"\r\n        @close=\"close\"\r\n        append-to-body\r\n        top=\"7vh\"\r\n    >\r\n        <form autocomplete=\"off\" @submit.prevent=\"submit\">\r\n            <div class=\"form-body\">\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-12\" v-if=\"warehouses\">\r\n                        <table class=\"table\">\r\n                            <thead>\r\n                                <tr>\r\n                                    <th>#</th>\r\n                                    <th>Ubicación</th>\r\n                                    <th class=\"text-right\">Stock</th>\r\n                                </tr>\r\n                            </thead>\r\n                            <tbody>\r\n                                <tr\r\n                                    v-for=\"(row, index) in warehouses\"\r\n                                    :key=\"index\"\r\n                                >\r\n                                    <th>{{ index + 1 }}</th>\r\n                                    <th>{{ row.warehouse_description }}</th>\r\n                                    <th class=\"text-right\">{{ row.stock }}</th>\r\n                                </tr>\r\n                            </tbody>\r\n                        </table>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n            <div class=\"form-actions text-right pt-2\">\r\n                <el-button @click.prevent=\"close()\">Cerrar</el-button>\r\n            </div>\r\n        </form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nexport default {\r\n    props: [\"showDialog\", \"warehouses\"],\r\n    data() {\r\n        return {\r\n            showImportDialog: false,\r\n            resource: \"items\",\r\n            recordId: null,\r\n            titleDialog: \"Productos\"\r\n        };\r\n    },\r\n    created() {\r\n        console.log(this.typeUser);\r\n    },\r\n    methods: {\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/components/WarehousesDetail.vue","<template>\r\n    <el-dialog :close-on-click-modal=\"false\"\r\n               :title=\"titleDialog\"\r\n               :visible=\"showDialog\"\r\n               append-to-body\r\n               @close=\"close\"\r\n               @open=\"create\">\r\n        <form autocomplete=\"off\"\r\n              @submit.prevent=\"submit\">\r\n            <div class=\"form-body\">\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-12\">\r\n                        <div :class=\"{'has-danger': errors.address}\"\r\n                             class=\"form-group\">\r\n                            <label class=\"control-label\">Dirección</label>\r\n                            <el-input v-model=\"form.address\"></el-input>\r\n                            <small v-if=\"errors.address\"\r\n                                   class=\"form-control-feedback\"\r\n                                   v-text=\"errors.address[0]\"></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-12\">\r\n                        <div :class=\"{'has-danger': errors.location_id}\"\r\n                             class=\"form-group\">\r\n                            <label class=\"control-label\">Ubigeo</label>\r\n                            <el-cascader v-model=\"form.location_id\"\r\n                                         :options=\"locations\"\r\n                                         filterable></el-cascader>\r\n                            <small v-if=\"errors.location_id\"\r\n                                   class=\"form-control-feedback\"\r\n                                   v-text=\"errors.location_id[0]\"></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n            <div class=\"form-actions text-right mt-4\">\r\n                <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n                <el-button :loading=\"loading_submit\"\r\n                           native-type=\"submit\"\r\n                           type=\"primary\">Guardar\r\n                </el-button>\r\n            </div>\r\n        </form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\n\r\nexport default {\r\n    name: 'DispatchOriginAddressForm',\r\n    props: ['showDialog', 'recordId', 'external'],\r\n    data() {\r\n        return {\r\n            loading_submit: false,\r\n            titleDialog: null,\r\n            resource: 'origin_addresses',\r\n            errors: {},\r\n            form: {},\r\n            locations: []\r\n        }\r\n    },\r\n    async created() {\r\n        await this.getTables();\r\n        this.initForm()\r\n    },\r\n    methods: {\r\n        async getTables() {\r\n            await this.$http.get(`/${this.resource}/tables`)\r\n                .then(response => {\r\n                    this.locations = response.data.locations\r\n                })\r\n        },\r\n        initForm() {\r\n            this.errors = {}\r\n            this.form = {\r\n                id: null,\r\n                address: null,\r\n                location_id: [],\r\n                is_default: false,\r\n                is_active: true,\r\n            }\r\n        },\r\n        async create() {\r\n            this.initForm();\r\n            this.titleDialog = (this.recordId) ? 'Editar dirección de partida' : 'Nueva dirección de partida'\r\n            if (this.recordId) {\r\n                await this.$http.get(`/${this.resource}/record/${this.recordId}`)\r\n                    .then(response => {\r\n                        this.form = response.data.data\r\n                    })\r\n            }\r\n        },\r\n        async submit() {\r\n            this.loading_submit = true\r\n            await this.$http.post(`/${this.resource}`, this.form)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$message.success(response.data.message)\r\n                        this.$emit('success', response.data.id)\r\n                        this.close()\r\n                    } else {\r\n                        this.$message.error(response.data.message)\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.errors = error.response.data\r\n                    } else {\r\n                        console.log(error)\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading_submit = false\r\n                })\r\n        },\r\n        close() {\r\n            this.$emit('update:showDialog', false)\r\n        },\r\n    }\r\n}\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/dispatches/OriginAddress/Form.vue","<template>\r\n    <div class=\"card mb-0 pt-2 pt-md-0\">\r\n        <div class=\"card-header bg-primary\">\r\n            <h6 class=\"my-0 text-white\">Nueva Guía de Remisión</h6>\r\n        </div>\r\n        <div class=\"card-body\">\r\n            <form autocomplete=\"off\" @submit.prevent=\"submit\">\r\n                <div class=\"form-body\">\r\n                    <div class=\"row\">\r\n                        <div class=\"col-lg-2\">\r\n                            <div\r\n                                :class=\"{ 'has-danger': errors.establishment }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Establecimiento<span class=\"text-danger\">\r\n                                        *</span\r\n                                    ></label\r\n                                >\r\n                                <el-select\r\n                                    v-model=\"form.establishment_id\"\r\n                                    @change=\"changeEstablishment\"\r\n                                >\r\n                                    <el-option\r\n                                        v-for=\"(option, idx) in establishments\"\r\n                                        :key=\"idx\"\r\n                                        :label=\"option.description\"\r\n                                        :value=\"option.id\"\r\n                                    ></el-option>\r\n                                </el-select>\r\n                                <small\r\n                                    v-if=\"errors.establishment\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.establishment[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"col-lg-2\">\r\n                            <div\r\n                                :class=\"{ 'has-danger': errors.series }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Serie<span class=\"text-danger\">\r\n                                        *</span\r\n                                    ></label\r\n                                >\r\n                                <el-select\r\n                                    v-model=\"form.series\"\r\n                                    :disabled=\"generalDisabledSeries()\"\r\n                                >\r\n                                    <el-option\r\n                                        v-for=\"(option, idx) in series\"\r\n                                        :key=\"idx\"\r\n                                        :label=\"option.number\"\r\n                                        :value=\"option.number\"\r\n                                    ></el-option>\r\n                                </el-select>\r\n                                <small\r\n                                    v-if=\"errors.series\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.series[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"col-lg-2\">\r\n                            <div\r\n                                :class=\"{ 'has-danger': errors.date_of_issue }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Fecha de emisión<span class=\"text-danger\">\r\n                                        *</span\r\n                                    ></label\r\n                                >\r\n                                <el-date-picker\r\n                                    v-model=\"form.date_of_issue\"\r\n                                    :clearable=\"false\"\r\n                                    type=\"date\"\r\n                                    value-format=\"yyyy-MM-dd\"\r\n                                ></el-date-picker>\r\n                                <small\r\n                                    v-if=\"errors.date_of_issue\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.date_of_issue[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"col-lg-2\">\r\n                            <div\r\n                                :class=\"{\r\n                                    'has-danger': errors.date_of_shipping\r\n                                }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Fecha de traslado<span class=\"text-danger\">\r\n                                        *</span\r\n                                    ></label\r\n                                >\r\n                                <el-date-picker\r\n                                    v-model=\"form.date_of_shipping\"\r\n                                    :clearable=\"false\"\r\n                                    type=\"date\"\r\n                                    value-format=\"yyyy-MM-dd\"\r\n                                ></el-date-picker>\r\n                                <small\r\n                                    v-if=\"errors.date_of_shipping\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.date_of_shipping[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"col-lg-4\">\r\n                            <div\r\n                                :class=\"{ 'has-danger': errors.customer_id }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\">\r\n                                    Cliente<span class=\"text-danger\"> *</span>\r\n                                    <a\r\n                                        href=\"#\"\r\n                                        @click.prevent=\"\r\n                                            showDialogNewPerson = true\r\n                                        \"\r\n                                        >[+ Nuevo]</a\r\n                                    >\r\n                                </label>\r\n                                <el-select\r\n                                    v-model=\"form.customer_id\"\r\n                                    :loading=\"loading_search\"\r\n                                    :remote-method=\"searchRemoteCustomers\"\r\n                                    filterable\r\n                                    placeholder=\"Escriba el nombre o número de documento del cliente\"\r\n                                    popper-class=\"el-select-customers\"\r\n                                    remote\r\n                                    @change=\"changeCustomer\"\r\n                                    @keyup.enter.native=\"keyupCustomer\"\r\n                                >\r\n                                    <el-option\r\n                                        v-for=\"(option, idx) in customers\"\r\n                                        :key=\"idx\"\r\n                                        :label=\"option.description\"\r\n                                        :value=\"option.id\"\r\n                                    ></el-option>\r\n                                </el-select>\r\n                                <small\r\n                                    v-if=\"errors.customer_id\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.customer_id[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"col-lg-2\">\r\n                            <div\r\n                                :class=\"{\r\n                                    'has-danger': errors.transport_mode_type_id\r\n                                }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Modo de traslado<span class=\"text-danger\">\r\n                                        *</span\r\n                                    ></label\r\n                                >\r\n                                <el-select\r\n                                    v-model=\"form.transport_mode_type_id\"\r\n                                >\r\n                                    <el-option\r\n                                        v-for=\"(option,\r\n                                        idx) in transportModeTypes\"\r\n                                        :key=\"idx\"\r\n                                        :label=\"option.description\"\r\n                                        :value=\"option.id\"\r\n                                    ></el-option>\r\n                                </el-select>\r\n                                <small\r\n                                    v-if=\"errors.transport_mode_type_id\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.transport_mode_type_id[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"col-lg-4\">\r\n                            <div\r\n                                :class=\"{\r\n                                    'has-danger': errors.transfer_reason_type_id\r\n                                }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Motivo de traslado<span\r\n                                        class=\"text-danger\"\r\n                                    >\r\n                                        *</span\r\n                                    ></label\r\n                                >\r\n                                <el-select\r\n                                    v-model=\"form.transfer_reason_type_id\"\r\n                                    @change=\"changeTransferReasonType\"\r\n                                >\r\n                                    <el-option\r\n                                        v-for=\"(option,\r\n                                        idx) in transferReasonTypes\"\r\n                                        :key=\"idx\"\r\n                                        :label=\"option.description\"\r\n                                        :value=\"option.id\"\r\n                                    ></el-option>\r\n                                </el-select>\r\n                                <small\r\n                                    v-if=\"errors.transfer_reason_type_id\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.transfer_reason_type_id[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                        <!-- numero de DAM -->\r\n                        <template v-if=\"form.transfer_reason_type_id === '09'\">\r\n                            <div class=\"col-lg-3\">\r\n                                <div\r\n                                    :class=\"{\r\n                                        'has-danger': errors['related.number']\r\n                                    }\"\r\n                                    class=\"form-group\"\r\n                                >\r\n                                    <label class=\"control-label\"\r\n                                        >Número de documento (DAM)\r\n                                        <el-tooltip\r\n                                            class=\"item\"\r\n                                            content=\"Formato del campo: XXXX-XX-XXX-XXXXXX, Ejemplo: 0001-01-002-001234\"\r\n                                            effect=\"dark\"\r\n                                            placement=\"top\"\r\n                                        >\r\n                                            <i class=\"fa fa-info-circle\"></i>\r\n                                        </el-tooltip>\r\n                                        <span class=\"text-danger\"> *</span>\r\n                                    </label>\r\n                                    <el-input\r\n                                        v-model=\"form.related.number\"\r\n                                        placeholder=\"0001-01-002-001234\"\r\n                                    ></el-input>\r\n                                    <small\r\n                                        v-if=\"errors['related.number']\"\r\n                                        class=\"form-control-feedback\"\r\n                                        v-text=\"errors['related.number'][0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"col-lg-3\">\r\n                                <div\r\n                                    :class=\"{\r\n                                        'has-danger':\r\n                                            errors['related.document_type_id']\r\n                                    }\"\r\n                                    class=\"form-group\"\r\n                                >\r\n                                    <label class=\"control-label\"\r\n                                        >Tipo documento relacionado<span\r\n                                            class=\"text-danger\"\r\n                                        >\r\n                                      