-md-4 d-flex align-items-end\"\r\n                                        v-if=\"\r\n                                            form.unit_type_id != 'ZZ' &&\r\n                                                form.series_enabled\r\n                                        \"\r\n                                    >\r\n                                        <div\r\n                                            class=\"form-group \"\r\n                                            :class=\"{\r\n                                                'has-danger': errors.lot_code\r\n                                            }\"\r\n                                        >\r\n                                            <label class=\"control-label\">\r\n                                                Ingrese series\r\n                                            </label>\r\n\r\n                                            <el-button\r\n                                                style=\"margin-top:2%;margin-left:15px;\"\r\n                                                type=\"primary\"\r\n                                                icon=\"el-icon-edit-outline\"\r\n                                                @click.prevent=\"clickLotcode\"\r\n                                            ></el-button>\r\n\r\n                                            <small\r\n                                                class=\"text-danger\"\r\n                                                v-if=\"errors.lot_code\"\r\n                                                v-text=\"errors.lot_code[0]\"\r\n                                            ></small>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"col-md-4\">\r\n                                    <div\r\n                                        v-show=\"form.unit_type_id != 'ZZ'\"\r\n             