\n                                                    Descripción\r\n                                                </th>\r\n                                                <th\r\n                                                    width=\"13%\"\r\n                                                    class=\"text-center\"\r\n                                                >\r\n                                                    Cantidad\r\n                                                    <el-tooltip\r\n                                                        class=\"item\"\r\n                                                        effect=\"dark\"\r\n                                                        content=\"Cantidad de unidades\"\r\n                                                        placement=\"top\"\r\n                                                    >\r\n                                                        <i\r\n                                                            class=\"fa fa-info-circle\"\r\n                                                        ></i>\r\n                                                    </el-tooltip>\r\n                                                </th>\r\n                                                <th\r\n                                                    width=\"13%\"\r\n                                                    class=\"text-center\"\r\n                                                >\r\n                                                    Precio\r\n                                                    <br />\r\n                                                    unitario\r\n                                                </th>\r\n                                                <th\r\n                                                    width=\"13%\"\r\n                                                    class=\"text-center\"\r\n                                                >\r\n                                                    Total\r\n                                                </th>\r\n                                                <th class=\"text-center\">\r\n                                                    Almacen\r\n                                                </th>\r\n                                                <!-- <th class=\"text-center\">\r\n                                                    P. Defecto\r\n                                                </th> -->\r\n                                                <th>Max.<br />Cant.</th>\r\n                                            </tr>\r\n                                        </thead>\r\n                                        <tbody>\r\n                                            <tr\r\n                                                v-for=\"(row,\r\n                                                index) in form.item_unit_types\"\r\n                                                :key=\"index\"\r\n                                            >\r\n                                                <template v-if=\"row.id\">\r\n                                                    <td class=\"text-center\">\r\n                                                        {{ row.unit_type_id }}\r\n                                                    </td>\r\n                                                    <td class=\"text-center\">\r\n                                                        {{ row.description }}\r\n                                                    </td>\r\n                                                    <td class=\"text-center\">\r\n                                                        {{ row.quantity_unit }}\r\n                                                    </td>\r\n                                                    <td class=\"text-center\">\r\n                                                        <el-input\r\n                                                            v-model=\"row.price2\"\r\n                                                            @input=\"\r\n                                                                undToTotal(\r\n                                                                    index,\r\n                                                                    row.price2,\r\n                                                                    row.quantity_unit\r\n                                                                )\r\n                                                            \"\r\n                                                        >\r\n                                                            <i\r\n                                                                slot=\"prefix\"\r\n                                                                class=\"el-icon-edit-outline\"\r\n                                                            ></i\r\n                                                        ></el-input>\r\n                                                    </td>\r\n                                                    <td class=\"text-center\">\r\n                                                        <el-input\r\n                                                            v-model=\"row.total\"\r\n                                                            @input=\"\r\n                                                                totalToUnd(\r\n                                                                    index,\r\n                                                                    row.total,\r\n                                                                    row.quantity_unit\r\n                                                                )\r\n                                                            \"\r\n                                                        >\r\n                                                            <i\r\n                                                                slot=\"prefix\"\r\n                                                                class=\"el-icon-edit-outline\"\r\n                                                            ></i\r\n                                                        ></el-input>\r\n\r\n                                                        <!-- <td class=\"text-center\">\r\n                                                        Precio\r\n                                                        {{ row.price_default }}\r\n                                                    </td> -->\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <el-select\r\n                                                            clearable\r\n                                                            v-model=\"\r\n                                                                row.warehouse_id\r\n                                                            \"\r\n                                                        >\r\n                                                            <el-option\r\n                                                                v-for=\"w in warehouses\"\r\n                                                                :key=\"w.id\"\r\n                                                                :value=\"w.id\"\r\n                                                                :label=\"\r\n                                                                    w.description\r\n                                                                \"\r\n                                                            ></el-option>\r\n                                                        </el-select>\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <el-checkbox\r\n                                                            v-model=\"\r\n                                                                row.selected\r\n                                                            \"\r\n                                                            @change=\"\r\n                                                                selectedMax(\r\n                                                                    index\r\n                                                                )\r\n                                                            \"\r\n                                                        ></el-checkbox>\r\n                                                    </td>\r\n\r\n                                                    <td\r\n                                                        class=\"series-table-actions text-end\"\r\n                                                    >\r\n                                                        <button\r\n                                                            type=\"button\"\r\n                                                            class=\"btn waves-effect waves-light btn-sm btn-danger\"\r\n                                                            @click.prevent=\"\r\n                                                                clickDelete(\r\n                                                                    row.id\r\n                                                                )\r\n                                                            \"\r\n                                                        >\r\n                                                            <i\r\n                                                                class=\"fa fa-trash\"\r\n                                                            ></i>\r\n                                                        </button>\r\n                                                    </td>\r\n                                                </template>\r\n                                                <template v-else>\r\n                                                    <td>\r\n                                                        <div class=\"form-group\">\r\n                                                            <el-select\r\n                                                                v-model=\"\r\n                                                                    row.unit_type_id\r\n                                                                \"\r\n                                                                dusk=\"item_unit_type.unit_type_id\"\r\n                                                            >\r\n                                                                <el-option\r\n                                                                    v-for=\"option in unit_types\"\r\n                                                                    :key=\"\r\n                                                                        option.id\r\n                                                                    \"\r\n                                                                    :value=\"\r\n                                                                        option.id\r\n                                                                    \"\r\n                                                                    :label=\"\r\n                                                                        option.description\r\n                                                                    \"\r\n                                                                ></el-option>\r\n                                                            </el-select>\r\n                                                        </div>\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <div class=\"form-group\">\r\n                                                            <el-input\r\n                                                                v-model=\"\r\n                                                                    row.description\r\n                                                                \"\r\n                                                            >\r\n                                                                <i\r\n                                                                    slot=\"prefix\"\r\n                                                                    class=\"el-icon-edit-outline\"\r\n                                                                ></i\r\n                                                            ></el-input>\r\n                                                        </div>\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <div class=\"form-group\">\r\n                                                            <el-input\r\n                                                                @input=\"\r\n                                                                    undToTotal(\r\n                                                                        index,\r\n                                                                        row.price2,\r\n                                                                        row.quantity_unit\r\n                                                                    )\r\n                                                                \"\r\n                                                                v-model=\"\r\n                                                                    row.quantity_unit\r\n                                                                \"\r\n                                                            >\r\n                                                                <i\r\n                                                                    slot=\"prefix\"\r\n                                                                    class=\"el-icon-edit-outline\"\r\n                                                                ></i\r\n                                                            ></el-input>\r\n                                                        </div>\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <div class=\"form-group\">\r\n                                                            <el-input\r\n                                                                v-model=\"\r\n                                                                    row.price2\r\n                                                                \"\r\n                                                                @input=\"\r\n                                                                    undToTotal(\r\n                                                                        index,\r\n                                                                        row.price2,\r\n                                                                        row.quantity_unit\r\n                                                                    )\r\n                                                                \"\r\n                                                            >\r\n                                                                <i\r\n                                                                    slot=\"prefix\"\r\n                                                                    class=\"el-icon-edit-outline\"\r\n                                                                ></i\r\n                                                            ></el-input>\r\n                                                        </div>\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <div class=\"form-group\">\r\n                                                            <el-input\r\n                                                                v-model=\"\r\n                                                                    row.total\r\n                                                                \"\r\n                                                                @input=\"\r\n                                                                    totalToUnd(\r\n                                                                        index,\r\n                                                                        row.total,\r\n                                                                        row.quantity_unit\r\n                                                                    )\r\n                                                                \"\r\n                                                            >\r\n                                                                <i\r\n                                                                    slot=\"prefix\"\r\n                                                                    class=\"el-icon-edit-outline\"\r\n                                                                ></i\r\n                                                            ></el-input>\r\n                                                        </div>\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <el-select\r\n                                                            clearable\r\n                                                            v-model=\"\r\n                                                                row.warehouse_id\r\n                                                            \"\r\n                                                        >\r\n                                                            <el-option\r\n                                                                v-for=\"w in warehouses\"\r\n                                                                :key=\"w.id\"\r\n                                                                :value=\"w.id\"\r\n                                                                :label=\"\r\n                                                                    w.description\r\n                                                                \"\r\n                                                            ></el-option>\r\n                                                        </el-select>\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <el-checkbox\r\n                                                            v-model=\"\r\n                                                                row.selected\r\n                                                            \"\r\n                                                            @change=\"\r\n                                                                selectedMax(\r\n                                                                    index\r\n                                                                )\r\n                                                            \"\r\n                                                        ></el-checkbox>\r\n                                                    </td>\r\n                                                    <td\r\n                                                        class=\"series-table-actions text-end\"\r\n                                                    >\r\n                                                        <button\r\n                                                            type=\"button\"\r\n                                                            class=\"btn waves-effect waves-light btn-sm btn-danger\"\r\n                                                            @click.prevent=\"\r\n                                                                clickCancel(\r\n                                                                    index\r\n                                                                )\r\n                                                            \"\r\n                                                        >\r\n                                                            <i\r\n                                                                class=\"fa fa-trash\"\r\n                                                            ></i>\r\n                                                        </button>\r\n                                                    </td>\r\n                                                </template>\r\n                                            </tr>\r\n                                        </tbody>\r\n                                    </table>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                    </el-tab-pane>\r\n\r\n                    <!-- <el-tab-pane label=\"Atributos\">\r\n                        <div class=\"row\">\r\n                            <div class=\"col-md-12\">\r\n                                <h6 class=\"separator-title\">\r\n                                    Campos adicionales\r\n                                </h6>\r\n                            </div>\r\n                            <div class=\"row col-md-12\">\r\n                                <div class=\"col-md-3\">\r\n                                    <div class=\"form-group\">\r\n                                        <label class=\"control-label\">Imágen\r\n                                            <span class=\"text-danger\"></span></label>\r\n                                        <el-upload class=\"avatar-uploader\" :data=\"{ type: 'items' }\" :headers=\"headers\"\r\n                                            :action=\"`/${resource}/uploads`\" :show-file-list=\"false\"\r\n                                            :on-success=\"onSuccess\">\r\n                                            <img v-if=\"form.image_url\" :src=\"form.image_url\" class=\"avatar\" />\r\n                                            <i v-else class=\"el-icon-plus avatar-uploader-icon\"></i>\r\n                                        </el-upload>\r\n                                    </div>\r\n                                </div>\r\n\r\n                                <div class=\"col-md-9\">\r\n                                    <div class=\"row\">\r\n                                        <div class=\"col-md-6\">\r\n                                            <div class=\"form-group\" :class=\"{\r\n                                                'has-danger':\r\n                                                    errors.brand_id\r\n                                            }\">\r\n                                                <label class=\"control-label\">\r\n                                                    Marca\r\n                                                </label>\r\n\r\n                                                <a href=\"#\" v-if=\"\r\n                                                    form_brand.add == false\r\n                                                \" class=\"control-label font-weight-bold text-info\" @click=\"    form_brand.add = true\">\r\n                                                    [ + Nuevo]</a>\r\n                                                <a href=\"#\" v-if=\"\r\n                                                    form_brand.add == true\r\n                                                \" class=\"control-label font-weight-bold text-info\"\r\n                                                    @click=\"saveBrand()\">\r\n                                                    [ + Guardar]</a>\r\n                                                <a href=\"#\" v-if=\"\r\n                                                    form_brand.add == true\r\n                                                \" class=\"control-label font-weight-bold text-danger\" @click=\"    form_brand.add = false\">\r\n                                                    [ Cancelar]</a>\r\n                                                <el-input v-if=\"\r\n                                                    form_brand.add == true\r\n                                                \" v-model=\"form_brand.name\" dusk=\"item_code\"\r\n                                                    style=\"margin-bottom:1.5%;\">\r\n                                                    <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i></el-input>\r\n\r\n                                                <el-select v-if=\"\r\n                                                    form_brand.add == false\r\n                                                \" v-model=\"form.brand_id\" filterable clearable>\r\n                                                    <el-option v-for=\"option in brands\" :key=\"option.id\"\r\n                                                        :value=\"option.id\" :label=\"option.name\"></el-option>\r\n                                                </el-select>\r\n                                                <small class=\"text-danger\" v-if=\"errors.brand_id\"\r\n                                                    v-text=\"errors.brand_id[0]\"></small>\r\n                                            </div>\r\n                                        </div>\r\n                                        <div v-if=\"attribute_types.length > 0\" class=\"col-md-12\">\r\n                                            <h6 class=\"separator-title \">\r\n                                                Atributos\r\n                                                <el-tooltip class=\"item\" effect=\"dark\"\r\n                                                    content=\"Diferentes presentaciones para la venta del producto\"\r\n                                                    placement=\"top\">\r\n                                                    <i class=\"fa fa-info-circle\"></i>\r\n                                                </el-tooltip>\r\n                                                <a href=\"#\" class=\"control-label font-weight-bold text-info\"\r\n                                                    @click.prevent=\"\r\n                                                        clickAddAttribute\r\n                                                    \">[+ Agregar]</a>\r\n                                            </h6>\r\n                                        </div>\r\n                                        <div v-if=\"form.attributes.length > 0\" class=\"col-md-12\">\r\n                                            <div class=\"table-responsive\">\r\n                                                <table class=\"table\">\r\n                                                    <thead>\r\n                                                        <tr>\r\n                                                            <th>Tipo</th>\r\n                                                            <th>Descripción</th>\r\n                                                            <th></th>\r\n                                                        </tr>\r\n                                                    </thead>\r\n                                                    <tbody>\r\n                                                        <tr v-for=\"(row, index) in form.attributes\" :key=\"index\">\r\n                                                            <td>\r\n                                                                <el-select v-model=\"\r\n                                                                    row.attribute_type_id\r\n                                                                \" filterable @change=\"    changeAttributeType(        index    )\">\r\n                                                                    <el-option v-for=\"option in attribute_types\" :key=\"\r\n                                                                        option.id\r\n                                                                    \" :value=\"    option.id\" :label=\"    option.description\">\r\n                                                                    </el-option>\r\n                                                                </el-select>\r\n                                                            </td>\r\n                                                            <td>\r\n                                                                <el-input v-model=\"\r\n                                                                    row.value\r\n                                                                \">\r\n                                                                    <i slot=\"prefix\"\r\n                                                                        class=\"el-icon-edit-outline\"></i></el-input>\r\n                                                            </td>\r\n                                                            <td>\r\n                                                                <button type=\"button\" class=\"btn btn-danger\"\r\n                                                                    @click.prevent=\"\r\n                                                                        clickRemoveAttribute(\r\n                                                                            index       ) \">   x\r\n                                                                </button>\r\n                                                            </td>\r\n                                                        </tr>\r\n                                                    </tbody>\r\n                                                </table>\r\n                                            </div>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                    </el-tab-pane> -->\r\n                    <el-tab-pane label=\"Compras\">\r\n                        <div class=\"row\">\r\n                            <div class=\"short-div col-md-8\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger':\r\n                                            errors.purchase_affectation_igv_type_id\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\"\r\n                                        >Tipo de afectación (Compra)</label\r\n                                    >\r\n                                    <el-select\r\n                                        v-model=\"\r\n                                            form.purchase_affectation_igv_type_id\r\n                                        \"\r\n                                    >\r\n                                        <el-option\r\n                                            v-for=\"option in affectation_igv_types\"\r\n                                            :key=\"option.id\"\r\n                                            :value=\"option.id\"\r\n                                            :label=\"option.description\"\r\n                                        ></el-option>\r\n                                    </el-select>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"\r\n                                            errors.purchase_affectation_igv_type_id\r\n                                        \"\r\n                                        v-text=\"\r\n                                            errors\r\n                                                .purchase_affectation_igv_type_id[0]\r\n                                        \"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n\r\n                            <div class=\"short-div col-md-4\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger': errors.purchase_unit_price\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\"\r\n                                        >Precio Unitario (Compra)</label\r\n                                    >\r\n                                    <el-input\r\n                                        v-model=\"form.purchase_unit_price\"\r\n                                        dusk=\"purchase_unit_price\"\r\n                                        @input=\"\r\n                                            calculatePercentageOfProfitByPurchase\r\n                                        \"\r\n                                    >\r\n                                        <i\r\n                                            slot=\"prefix\"\r\n                                            class=\"el-icon-edit-outline\"\r\n                                        ></i\r\n                                    ></el-input>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.purchase_unit_price\"\r\n                                        v-text=\"errors.purchase_unit_price[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"short-div col-md-4\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger':\r\n                                            errors.percentage_of_profit\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\">\r\n                                        <el-checkbox\r\n                                            v-model=\"\r\n                                                enabled_percentage_of_profit\r\n                                            \"\r\n                                            @change=\"\r\n                                                changeEnabledPercentageOfProfit\r\n                                            \"\r\n                                        ></el-checkbox>\r\n                                        Porcentaje de ganancia (%)\r\n                                    </label>\r\n                                    <el-input\r\n                                        v-model=\"form.percentage_of_profit\"\r\n                                        :disabled=\"\r\n                                            !enabled_percentage_of_profit\r\n                                        \"\r\n                                        @input=\"\r\n                                            calculatePercentageOfProfitByPercentage\r\n                                        \"\r\n                                    >\r\n                                        <i\r\n                                            slot=\"prefix\"\r\n                                            class=\"el-icon-edit-outline\"\r\n                                        ></i\r\n                                    ></el-input>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.percentage_of_profit\"\r\n                                        v-text=\"errors.percentage_of_profit[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                    </el-tab-pane>\r\n                </el-tabs>\r\n            </div>\r\n            <div class=\"form-actions text-end pt-2 pb-2\">\r\n                <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n                <el-button\r\n                    type=\"primary\"\r\n                    native-type=\"submit\"\r\n                    :loading=\"loading_submit\"\r\n                    >Guardar</el-button\r\n                >\r\n            </div>\r\n        </form>\r\n        <!-- <percentage-perception\r\n                :showDialog.sync=\"showPercentagePerception\"\r\n                :percentage_perception=\"percentage_perception\">\r\n        </percentage-perception> -->\r\n\r\n        <lots-form\r\n            :showDialog.sync=\"showDialogLots\"\r\n            :stock=\"form.stock\"\r\n            :recordId=\"recordId\"\r\n            :lots=\"form.lots\"\r\n            @addRowLot=\"addRowLot\"\r\n        >\r\n        </lots-form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\n// import PercentagePerception from './partials/percentage_perception.vue'\r\nimport LotsForm from \"./partials/lots.vue\";\r\n\r\nexport default {\r\n    props: [\"showDialog\", \"recordId\", \"external\", \"worker\"],\r\n    components: { LotsForm },\r\n\r\n    data() {\r\n        return {\r\n            allEstablishment: false,\r\n            showDialogLots: false,\r\n            form_category: { add: false, name: null, id: null },\r\n            form_brand: { add: false, name: null, id: null },\r\n            warehouses: [],\r\n            loading_submit: false,\r\n            showPercentagePerception: false,\r\n            has_percentage_perception: false,\r\n            percentage_perception: null,\r\n            enabled_percentage_of_profit: false,\r\n            titleDialog: null,\r\n            resource: \"items\",\r\n            errors: {},\r\n            headers: headers_token,\r\n            form: {promotion_count: null },\r\n            configuration: {},\r\n            unit_types: [],\r\n            areas: [],\r\n            currency_types: [],\r\n            system_isc_types: [],\r\n            affectation_igv_types: [],\r\n            categories: [],\r\n            brands: [],\r\n            accounts: [],\r\n            show_has_igv: true,\r\n            have_account: false,\r\n            showSeries: false,\r\n            item_unit_type: {\r\n                id: null,\r\n                unit_type_id: null,\r\n                quantity_unit: 0,\r\n                price1: 0,\r\n                price2: 0,\r\n                price3: 0,\r\n                price_default: 2\r\n            },\r\n            attribute_types: [],\r\n            area_id: 2\r\n        };\r\n    },\r\n    async created() {\r\n        await this.initForm();\r\n        await this.$http.get(`/${this.resource}/tables`).then(response => {\r\n            this.unit_types = response.data.unit_types;\r\n            this.accounts = response.data.accounts;\r\n            this.currency_types = response.data.currency_types;\r\n            this.system_isc_types = response.data.system_isc_types;\r\n            this.affectation_igv_types = response.data.affectation_igv_types;\r\n            this.warehouses = response.data.warehouses;\r\n            if (this.warehouses.length > 0) {\r\n                this.form.warehouse_id = this.warehouses[0].id;\r\n                this.form.warehouse_prices = this.warehouses.map(w => ({\r\n                    id: null,\r\n                    item_id: null,\r\n                    warehouse_id: w.id,\r\n                    price: null,\r\n                    warehouse: w.description\r\n                }));\r\n            }\r\n            if (this.worker) {\r\n                this.warehouses = this.warehouses.filter(\r\n                    w => w.establishment_id == this.worker.establishment_id\r\n                );\r\n                this.form.warehouse_id = this.warehouses[0].id;\r\n            }\r\n            this.categories = response.data.categories;\r\n            this.brands = response.data.brands;\r\n            this.attribute_types = response.data.attribute_types;\r\n            this.configuration = response.data.configuration;\r\n            this.areas = response.data.areas;\r\n\r\n            this.form.sale_affectation_igv_type_id =\r\n                this.affectation_igv_types.length > 0\r\n                    ? this.affectation_igv_types[0].id\r\n                    : null;\r\n            this.form.purchase_affectation_igv_type_id =\r\n                this.affectation_igv_types.length > 0\r\n                    ? this.affectation_igv_types[0].id\r\n                    : null;\r\n\r\n            if (!this.configuration.restaurant) {\r\n                this.areas = this.areas.filter(\r\n                    a =>\r\n                        ![\"BARRA\", \"COCINA\", \"MOZO\", \"MESA\"].some(\r\n                            p => p == a.description\r\n                        )\r\n                );\r\n            }\r\n            //agregar opciones para entorno restaurante\r\n        });\r\n\r\n        this.$eventHub.$on(\"submitPercentagePerception\", data => {\r\n            this.form.percentage_perception = data;\r\n            if (!this.form.percentage_perception)\r\n                this.has_percentage_perception = false;\r\n        });\r\n\r\n        this.$eventHub.$on(\"reloadTables\", () => {\r\n            this.reloadTables();\r\n        });\r\n\r\n        await this.setDefaultConfiguration();\r\n    },\r\n\r\n    methods: {\r\n        selectedMax(idx) {\r\n            let selected = this.form.item_unit_types[idx].selected;\r\n            for (let i = 0; i < this.form.item_unit_types.length; i++) {\r\n                let it = this.form.item_unit_types[i];\r\n                it.selected = false;\r\n            }\r\n\r\n            this.form.item_unit_types[idx].selected = selected;\r\n            if (selected) {\r\n                let qty = Number(this.form.item_unit_types[idx].quantity_unit);\r\n                !isNaN(qty) && (this.form.max_quantity = qty);\r\n            } else {\r\n                this.form.max_quantity = null;\r\n            }\r\n            this.$forceUpdate();\r\n        },\r\n        undToTotal(idx, amount, qty) {\r\n            let arr = this.form.item_unit_types;\r\n            if (qty > 0) {\r\n                arr[idx].total = Number(amount) * Number(qty);\r\n            } else {\r\n                this.$toast.warning(\"Ingrese una cantidad válida\");\r\n                arr[idx].price2 = 0;\r\n            }\r\n        },\r\n        totalToUnd(idx, amount, qty) {\r\n            let arr = this.form.item_unit_types;\r\n            if (qty > 0) {\r\n                arr[idx].price2 = Number(amount) / Number(qty);\r\n            } else {\r\n                this.$toast.warning(\"Ingrese una cantidad válida\");\r\n                arr[idx].total = 0;\r\n            }\r\n        },\r\n        setDefaultConfiguration() {\r\n            this.form.sale_affectation_igv_type_id = this.configuration\r\n                ? this.configuration.affectation_igv_type_id\r\n                : \"10\";\r\n\r\n            this.$http.get(`/configurations/record`).then(response => {\r\n                this.form.has_igv = response.data.data.include_igv;\r\n            });\r\n            this.changeAffectationIgvType();\r\n        },\r\n        clickAddAttribute() {\r\n            this.form.attributes.push({\r\n                attribute_type_id: null,\r\n                description: null,\r\n                value: null,\r\n                start_date: null,\r\n                end_date: null,\r\n                duration: null\r\n            });\r\n        },\r\n        async reloadTables() {\r\n            await this.$http.get(`/${this.resource}/tables`).then(response => {\r\n                this.unit_types = response.data.unit_types;\r\n                this.accounts = response.data.accounts;\r\n                this.currency_types = response.data.currency_types;\r\n                this.system_isc_types = response.data.system_isc_types;\r\n                this.affectation_igv_types =\r\n                    response.data.affectation_igv_types;\r\n                this.warehouses = response.data.warehouses;\r\n                this.categories = response.data.categories;\r\n                this.brands = response.data.brands;\r\n\r\n                this.form.sale_affectation_igv_type_id =\r\n                    this.affectation_igv_types.length > 0\r\n                        ? this.affectation_igv_types[0].id\r\n                        : null;\r\n                this.form.purchase_affectation_igv_type_id =\r\n                    this.affectation_igv_types.length > 0\r\n                        ? this.affectation_igv_types[0].id\r\n                        : null;\r\n            });\r\n        },\r\n        changeLotsEnabled() {\r\n            // if(!this.form.lots_enabled){\r\n            //     this.form.lot_code = null\r\n            //     this.form.lots = []\r\n            // }\r\n        },\r\n        addRowLot(lots) {\r\n            this.form.lots = lots;\r\n        },\r\n        clickLotcode() {\r\n            // if(this.form.stock <= 0)\r\n            //     return this.$toast.error('El stock debe ser mayor a 0')\r\n\r\n            this.showDialogLots = true;\r\n        },\r\n        changeHaveAccount() {\r\n            if (!this.have_account) this.form.account_id = null;\r\n        },\r\n        changeEnabledPercentageOfProfit() {\r\n            // if(!this.enabled_percentage_of_profit) this.form.percentage_of_profit = 0\r\n        },\r\n        clickDelete(id) {\r\n            this.$http\r\n                .delete(`/${this.resource}/item-unit-type/${id}`)\r\n                .then(res => {\r\n                    if (res.data.success) {\r\n                        this.loadRecord();\r\n                        this.$toast.success(\r\n                            \"Se eliminó correctamente el registro\"\r\n                        );\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 500) {\r\n                        this.$toast.error(\"Error al intentar eliminar\");\r\n                    } else {\r\n                        console.log(error.response.data.message);\r\n                    }\r\n                });\r\n        },\r\n        changeHasPerception() {\r\n            if (!this.form.has_perception) {\r\n                this.form.percentage_perception = null;\r\n            }\r\n        },\r\n        clickAddRow() {\r\n            this.form.item_unit_types.push({\r\n                id: null,\r\n                description: null,\r\n                unit_type_id: \"NIU\",\r\n                quantity_unit: 0,\r\n                price1: 0,\r\n                price2: 0,\r\n                price3: 0,\r\n                price_default: 2,\r\n                warehouse_id: null\r\n            });\r\n        },\r\n        clickCancel(index) {\r\n            this.form.item_unit_types.splice(index, 1);\r\n            // this.initDocumentTypes()\r\n            // this.showAddButton = true\r\n        },\r\n        initForm() {\r\n            (this.loading_submit = false), (this.errors = {});\r\n            this.form = {\r\n                id: null,\r\n                item_type_id: \"01\",\r\n                location: null,\r\n                internal_id: null,\r\n                item_code: null,\r\n                item_code_gs1: null,\r\n                description: null,\r\n                name: null,\r\n                second_name: null,\r\n                unit_type_id: \"NIU\",\r\n                currency_type_id: \"PEN\",\r\n                sale_unit_price: 0,\r\n                purchase_unit_price: 0,\r\n                has_isc: false,\r\n                system_isc_type_id: null,\r\n                percentage_isc: 0,\r\n                suggested_price: 0,\r\n                sale_affectation_igv_type_id: null,\r\n                purchase_affectation_igv_type_id: null,\r\n                calculate_quantity: false,\r\n                stock: 0,\r\n                stock_min: 1,\r\n                has_igv: true,\r\n                has_perception: false,\r\n                item_unit_types: [],\r\n                percentage_of_profit: 0,\r\n                percentage_perception: 0,\r\n                image: null,\r\n                image_url: null,\r\n                temp_path: null,\r\n                is_set: false,\r\n                account_id: null,\r\n                category_id: null,\r\n                brand_id: null,\r\n                date_of_due: null,\r\n                lot_code: null,\r\n                lots_enabled: false,\r\n                lots: [],\r\n                attributes: [],\r\n                series_enabled: false,\r\n                area_id: 2,\r\n                \r\n            };\r\n            this.show_has_igv = true;\r\n            this.enabled_percentage_of_profit = false;\r\n        },\r\n        onSuccess(response, file, fileList) {\r\n            if (response.success) {\r\n                this.form.image = response.data.filename;\r\n                this.form.image_url = response.data.temp_image;\r\n                this.form.temp_path = response.data.temp_path;\r\n            } else {\r\n                this.$toast.error(response.message);\r\n            }\r\n        },\r\n        changeAffectationIgvType() {\r\n            let affectation_igv_type_exonerated = [\r\n                20,\r\n                21,\r\n                30,\r\n                31,\r\n                32,\r\n                33,\r\n                34,\r\n                35,\r\n                36,\r\n                37\r\n            ];\r\n            let is_exonerated = affectation_igv_type_exonerated.includes(\r\n                parseInt(this.form.sale_affectation_igv_type_id)\r\n            );\r\n\r\n            if (is_exonerated) {\r\n                this.show_has_igv = false;\r\n                this.form.has_igv = true;\r\n            } else {\r\n                this.show_has_igv = true;\r\n            }\r\n        },\r\n        resetForm() {\r\n            this.initForm();\r\n            this.form.sale_affectation_igv_type_id =\r\n                this.affectation_igv_types.length > 0\r\n                    ? this.affectation_igv_types[0].id\r\n                    : null;\r\n            this.form.purchase_affectation_igv_type_id =\r\n                this.affectation_igv_types.length > 0\r\n                    ? this.affectation_igv_types[0].id\r\n                    : null;\r\n            this.setDefaultConfiguration();\r\n        },\r\n        create() {\r\n            this.titleDialog = this.recordId\r\n                ? \"Editar Productos\"\r\n                : \"Nuevo Producto\";\r\n\r\n            if (this.recordId) {\r\n                this.$http\r\n                    .get(`/${this.resource}/record/${this.recordId}`)\r\n                    .then(response => {\r\n                        this.form = response.data.data;\r\n\r\n                        if (this.form.warehouse_prices.length == 0) {\r\n                            if (this.warehouses.length > 0) {\r\n                                this.form.warehouse_id = this.warehouses[0].id;\r\n                                this.form.warehouse_prices = this.warehouses.map(\r\n                                    w => ({\r\n                                        id: null,\r\n                                        item_id: null,\r\n                                        warehouse_id: w.id,\r\n                                        price: null,\r\n                                        warehouse: w.description\r\n                                    })\r\n                                );\r\n                            }\r\n                        } else {\r\n                            this.form.warehouse_prices = this.warehouses.map(\r\n                                w => {\r\n                                    let exist = this.form.warehouse_prices.find(\r\n                                        ww => ww.warehouse_id == w.id\r\n                                    );\r\n                                    if (exist) {\r\n                                        return exist;\r\n                                    }\r\n                                    return {\r\n                                        id: null,\r\n                                        item_id: null,\r\n                                        warehouse_id: w.id,\r\n                                        price: null,\r\n                                        warehouse: w.description\r\n                                    };\r\n                                }\r\n                            );\r\n                        }\r\n                        if (this.form.item_unit_types.length != 0) {\r\n                            this.restoreUnitTypes();\r\n                        }\r\n                        this.has_percentage_perception = this.form\r\n                            .percentage_perception\r\n                            ? true\r\n                            : false;\r\n                        this.changeAffectationIgvType();\r\n                        this.showSeries = true;\r\n\r\n                        if (this.form.series_enabled == 1) {\r\n                            this.form.series_enabled = true;\r\n                        } else this.form.series_enabled = false;\r\n                    });\r\n            } else {\r\n                this.showSeries = true;\r\n                this.form.area_id = 2;\r\n            }\r\n            // if(!this.record){\r\n            //     this.form.has_igv= true\r\n            // }\r\n        },\r\n        restoreUnitTypes() {\r\n            let hasSelected = false;\r\n            this.form.item_unit_types = this.form.item_unit_types.map(i => {\r\n                let selected = false;\r\n                if (\r\n                    !hasSelected &&\r\n                    Number(this.form.max_quantity) == Number(i.quantity_unit)\r\n                ) {\r\n                    selected = true;\r\n                    hasSelected = true;\r\n                }\r\n                return {\r\n                    ...i,\r\n                    selected,\r\n                    total: (Number(i.price2) * Number(i.quantity_unit)).toFixed(\r\n                        2\r\n                    )\r\n                };\r\n            });\r\n        },\r\n        loadRecord() {\r\n            if (this.recordId) {\r\n                this.$http\r\n                    .get(`/${this.resource}/record/${this.recordId}`)\r\n                    .then(response => {\r\n                        this.form = response.data.data;\r\n                        this.changeAffectationIgvType();\r\n                    });\r\n            }\r\n        },\r\n        changeWarehouse() {\r\n            this.$toast.warning(\r\n                \"Cambió el destino del producto, verifique los PRECIOS DE ALMACÉN\"\r\n            );\r\n\r\n            let w = this.form.warehouse_prices.find(\r\n                ww => ww.warehouse_id == this.form.warehouse_id\r\n            );\r\n            if (w) {\r\n                w.price = this.form.sale_unit_price;\r\n            }\r\n\r\n            this.$forceUpdate();\r\n        },\r\n        calculatePercentageOfProfitBySale() {\r\n            let w = this.form.warehouse_prices.find(\r\n                ww => ww.warehouse_id == this.form.warehouse_id\r\n            );\r\n            if (w) {\r\n                w.price = this.form.sale_unit_price;\r\n            }\r\n            let difference =\r\n                parseFloat(this.form.sale_unit_price) -\r\n                parseFloat(this.form.purchase_unit_price);\r\n\r\n            if (parseFloat(this.form.purchase_unit_price) === 0) {\r\n                this.form.percentage_of_profit = 0;\r\n            } else {\r\n                if (this.enabled_percentage_of_profit)\r\n                    this.form.percentage_of_profit =\r\n                        (difference /\r\n                            parseFloat(this.form.purchase_unit_price)) *\r\n                        100;\r\n            }\r\n        },\r\n        calculatePercentageOfProfitByPurchase() {\r\n            if (this.form.percentage_of_profit === \"\") {\r\n                this.form.percentage_of_profit = 0;\r\n            }\r\n\r\n            if (this.enabled_percentage_of_profit)\r\n                this.form.sale_unit_price =\r\n                    (this.form.purchase_unit_price *\r\n                        (100 + parseFloat(this.form.percentage_of_profit))) /\r\n                    100;\r\n        },\r\n        calculatePercentageOfProfitByPercentage() {\r\n            if (this.form.percentage_of_profit === \"\") {\r\n                this.form.percentage_of_profit = 0;\r\n            }\r\n\r\n            if (this.enabled_percentage_of_profit)\r\n                this.form.sale_unit_price =\r\n                    (this.form.purchase_unit_price *\r\n                        (100 + parseFloat(this.form.percentage_of_profit))) /\r\n                    100;\r\n        },\r\n        async submit() {\r\n            if (this.form.internal_id == null || this.form.internal_id == \"\") {\r\n                this.$refs.internal_id.$el.querySelector(\"input\").focus();\r\n                return this.$toast.warning(\r\n                    \"No puede guardar Un nuevo Producto sin codigo interno \"\r\n                );\r\n            }\r\n\r\n            if (this.form.has_perception && !this.form.percentage_perception)\r\n                return this.$toast.error(\"Ingrese un porcentaje\");\r\n\r\n            if (!this.form.warehouse_id)\r\n                return this.$toast.error(\"Seleccione un almacen\");\r\n            if (!this.recordId && this.form.lots_enabled) {\r\n                // if (!this.form.lot_code)\r\n                //     return this.$toast.error(\"Código de lote es requerido\");\r\n                // if (!this.form.date_of_due)\r\n                //     return this.$toast.error(\r\n                //         \"Fecha de vencimiento es requerido si lotes esta habilitado.\"\r\n                //     );\r\n            }\r\n\r\n            if (!this.recordId && this.form.series_enabled) {\r\n                if (this.form.lots.length > this.form.stock)\r\n                    return this.$toast.error(\r\n                        \"La cantidad de series registradas es superior al stock\"\r\n                    );\r\n\r\n                if (this.form.lots.length != this.form.stock)\r\n                    return this.$toast.error(\r\n                        \"La cantidad de series registradas son diferentes al stock\"\r\n                    );\r\n            }\r\n\r\n            this.loading_submit = true;\r\n            this.form.all_establishment = this.allEstablishment;\r\n            \r\n            await this.$http\r\n                .post(`/${this.resource}`, this.form)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$toast.success(response.data.message);\r\n                        if (this.external) {\r\n                            this.$emit(\"add\", response.data.data);\r\n                            //this.$eventHub.$emit('reloadDataItems', response.data.id)\r\n                        } else {\r\n                            this.$eventHub.$emit(\"reloadData\");\r\n                        }\r\n                        this.close();\r\n                    } else {\r\n                        this.$toast.error(response.data.message);\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.errors = error.response.data.errors;\r\n                    } else {\r\n                        console.log(error);\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading_submit = false;\r\n                });\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n            this.showSeries = false;\r\n            this.resetForm();\r\n            this.form.warehouse_prices = this.warehouses.map(w => ({\r\n                id: null,\r\n                item_id: null,\r\n                warehouse_id: w.id,\r\n                price: null,\r\n                warehouse: w.description\r\n            }));\r\n        },\r\n        changeHasIsc() {\r\n            this.form.system_isc_type_id = null;\r\n            this.form.percentage_isc = 0;\r\n            this.form.suggested_price = 0;\r\n        },\r\n        changeSystemIscType() {\r\n            if (this.form.system_isc_type_id !== \"03\") {\r\n                this.form.suggested_price = 0;\r\n            }\r\n        },\r\n        saveCategory() {\r\n            this.form_category.add = false;\r\n\r\n            this.$http\r\n                .post(`/items/categories`, this.form_category)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$toast.success(response.data.message);\r\n                        this.categories.push(response.data.data);\r\n                        this.form.category_id = response.data.data.id;\r\n                        this.form_category.name = null;\r\n                    } else {\r\n                        this.$toast.error(\"No se guardaron los cambios\");\r\n                    }\r\n                })\r\n                .catch(error => {});\r\n        },\r\n        saveBrand() {\r\n            this.form_brand.add = false;\r\n\r\n            this.$http\r\n                .post(`/brands`, this.form_brand)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$toast.success(response.data.message);\r\n                        this.brands.push(response.data.data);\r\n                        this.form_brand.name = null;\r\n                    } else {\r\n                        this.$toast.error(\"No se guardaron los cambios\");\r\n                    }\r\n                })\r\n                .catch(error => {});\r\n        },\r\n        changeAttributeType(index) {\r\n            let attribute_type_id = this.form.attributes[index]\r\n                .attribute_type_id;\r\n            let attribute_type = _.find(this.attribute_types, {\r\n                id: attribute_type_id\r\n            });\r\n            this.form.attributes[index].description =\r\n                attribute_type.description;\r\n        },\r\n        clickRemoveAttribute(index) {\r\n            this.form.attributes.splice(index, 1);\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/items/form.vue","<template>\r\n    <el-dialog :title=\"titleDialog\" width=\"40%\"  :visible=\"showDialog\"  @open=\"create\"  :close-on-click-modal=\"false\" :close-on-press-escape=\"false\" append-to-body :show-close=\"false\">\r\n\r\n        <div class=\"form-body\">\r\n            <div class=\"row\" >\r\n                <div class=\"col-lg-12 col-md-12\">\r\n                    <table width=\"100%\">\r\n                        <thead>\r\n                            <tr width=\"100%\">\r\n                                <th v-if=\"lots.length>0\">Serie</th>\r\n                                <th v-if=\"lots.length>0\">Estado</th>\r\n                                <th v-if=\"lots.length>0\">Fecha</th>\r\n                                <th width=\"15%\"><a href=\"#\" @click.prevent=\"clickAddLot\" class=\"text-center font-weight-bold text-info\">[+ Agregar]</a></th>\r\n                            </tr>\r\n                        </thead>\r\n                        <tbody>\r\n                            <tr v-for=\"(row, index) in lots\" :key=\"index\" width=\"100%\" >\r\n                                <td>\r\n                                    <div class=\"form-group mb-2 mr-2\"  >\r\n                                        <el-input @blur=\"duplicateSerie(row.series, index)\" v-model=\"row.series\"> <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i></el-input>\r\n                                    </div>\r\n                                </td>\r\n                                 <td>\r\n                                    <div class=\"form-group mb-2 mr-2\"  >\r\n                                        <el-select  v-model=\"row.state\">\r\n                                            <el-option\r\n                                                v-for=\"(option, index) in states\"\r\n                                                :key=\"index\"\r\n                                                :value=\"option\"\r\n                                                :label=\"option\"\r\n                                            ></el-option>\r\n                                        </el-select>\r\n                                    </div>\r\n                                </td>\r\n                                <td>\r\n                                    <div class=\"form-group mb-2 mr-2\" >\r\n                                        <el-date-picker v-model=\"row.date\" type=\"date\" value-format=\"yyyy-MM-dd\" :clearable=\"false\"></el-date-picker>\r\n                                    </div>\r\n                                </td>\r\n                                <td class=\"series-table-actions text-center\">\r\n                                    <button  type=\"button\" class=\"btn waves-effect waves-light btn-sm btn-danger\" @click.prevent=\"clickCancel(index)\">\r\n                                        <i class=\"fa fa-trash\"></i>\r\n                                    </button>\r\n                                </td>\r\n                                <br>\r\n                            </tr>\r\n                        </tbody>\r\n                    </table>\r\n\r\n\r\n                </div>\r\n\r\n            </div>\r\n        </div>\r\n\r\n       <div class=\"form-actions text-end pt-2 pb-2\">\r\n            <el-button @click.prevent=\"clickCancelSubmit()\">Cancelar</el-button>\r\n            <el-button type=\"primary\" @click=\"submit\" >Guardar</el-button>\r\n        </div>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\n    export default {\r\n        props: ['showDialog', 'lots', 'stock','recordId'],\r\n        data() {\r\n            return {\r\n                titleDialog: 'Series',\r\n                loading: false,\r\n                errors: {},\r\n                form: {},\r\n                states: ['Activo', 'Inactivo', 'Desactivado', 'Voz', 'M2m']\r\n\r\n            }\r\n        },\r\n        async created() {\r\n\r\n            // await this.$http.get(`/pos/payment_tables`)\r\n            //     .then(response => {\r\n            //         this.payment_method_types = response.data.payment_method_types\r\n            //         this.cards_brand = response.data.cards_brand\r\n            //         this.clickAddLot()\r\n            //     })\r\n        },\r\n        methods: {\r\n            async duplicateSerie(data, index)\r\n            {\r\n\r\n                let duplicates = await _.filter(this.lots, {'series':data})\r\n                if(duplicates.length > 1)\r\n                {\r\n                    this.lots[index].series = ''\r\n                }\r\n            },\r\n            create(){\r\n\r\n                if(!this.recordId){\r\n\r\n                    if(this.lots.length == 0){\r\n\r\n                        this.addMoreLots(this.stock)\r\n\r\n                    }else{\r\n\r\n                        let quantity = this.stock - this.lots.length\r\n                        if(quantity > 0){\r\n                            this.addMoreLots(quantity)\r\n                        }\r\n                        // else{\r\n                        //     this.deleteMoreLots(quantity)\r\n                        // }\r\n                    }\r\n\r\n                }\r\n            },\r\n            addMoreLots(number){\r\n\r\n                for (let i = 0; i < number; i++) {\r\n                    this.clickAddLot()\r\n                }\r\n\r\n            },\r\n            deleteMoreLots(number){\r\n\r\n                for (let i = 0; i < number; i++) {\r\n                    this.lots.pop();\r\n                    this.$emit('addRowLot', this.lots);\r\n                }\r\n\r\n            },\r\n            async validateLots(){\r\n\r\n                let error = 0\r\n\r\n                await this.lots.forEach(element => {\r\n                    if(element.series == null){\r\n                        error++\r\n                    }\r\n                });\r\n\r\n                if(error>0)\r\n                    return {success:false, message:'El campo serie es obligatorio'}\r\n\r\n\r\n                return {success:true}\r\n\r\n            },\r\n            async submit(){\r\n\r\n                let val_lots = await this.validateLots()\r\n                if(!val_lots.success)\r\n                    return this.$toast.error(val_lots.message);\r\n\r\n                await this.$emit('addRowLot', this.lots);\r\n                await this.$emit('update:showDialog', false)\r\n\r\n            },\r\n            clickAddLot() {\r\n\r\n                if(!this.recordId){\r\n                    if(this.lots.length >= this.stock)\r\n                        return this.$toast.error('La cantidad de registros es superior al stock o cantidad');\r\n                }\r\n\r\n\r\n                this.lots.push({\r\n                    id: null,\r\n                    item_id: null,\r\n                    series: null,\r\n                    date:  moment().format('YYYY-MM-DD'),\r\n                    state: 'Activo'\r\n\r\n                });\r\n\r\n                this.$emit('addRowLot', this.lots);\r\n            },\r\n\r\n            close() {\r\n                this.$emit('update:showDialog', false)\r\n                this.$emit('addRowLot', this.lots);\r\n            },\r\n            clickCancel(index) {\r\n                this.lots.splice(index, 1);\r\n               // item.deleted = true\r\n                this.$emit('addRowLot', this.lots);\r\n            },\r\n\r\n            async clickCancelSubmit() {\r\n                this.$emit('addRowLot', []);\r\n                await this.$emit('update:showDialog', false)\r\n            },\r\n            close() {\r\n                this.$emit('update:showDialog', false)\r\n            },\r\n        }\r\n    }\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/items/partials/lots.vue","<template>\r\n    <el-dialog\r\n        :title=\"titleDialog\"\r\n    