utton>\r\n                                                    </td>\r\n                                                </template>\r\n                                                <template v-else>\r\n                                                    <td>\r\n                                                        <div class=\"form-group\">\r\n                                                            <el-select\r\n                                                                v-model=\"\r\n                                                                    row.unit_type_id\r\n                                                                \"\r\n                                                                dusk=\"item_unit_type.unit_type_id\"\r\n                                                            >\r\n                                                                <el-option\r\n                                                                    v-for=\"option in unit_types\"\r\n                                                                    :key=\"\r\n                                                                        option.id\r\n                                                                    \"\r\n                                                                    :value=\"\r\n                                                                        option.id\r\n                                                                    \"\r\n                                                                    :label=\"\r\n                                                                        option.description\r\n                                                                    \"\r\n                                                                ></el-option>\r\n                                                            </el-select>\r\n                                                        </div>\r\n                                          