                            :value=\"option\"\r\n                                                :label=\"option\"\r\n                                            ></el-option>\r\n                                        </el-select>\r\n                                    </div>\r\n                                </td>\r\n                                <td>\r\n                                    <div class=\"form-group mb-2 mr-2\" >\r\n                                        <el-date-picker v-model=\"row.date\" type=\"date\" value-format=\"yyyy-MM-dd\" :clearable=\"false\"></el-date-picker>\r\n                                    </div>\r\n                                </td>\r\n                                <td class=\"series-table-actions text-center\">\r\n                                    <button  type=\"button\" class=\"btn waves-effect waves-light btn-sm btn-danger\" @click.prevent=\"clickCancel(index)\">\r\n                                        <i class=\"fa fa-trash\"></i>\r\n                                    </button>\r\n                                </td>\r\n                                <br>\r\n                            </tr>\r\n                        </tbody>\r\n                    </table>\r\n\r\n\r\n                </div>\r\n\r\n            </div>\r\n        </div>\r\n\r\n       <div class=\"form-actions text-end pt-2 pb-2\">\r\n            <el-button @click.prevent=\"clickCancelSubmit()\">Cancelar</el-button>\r\n            <el-button type=\"primary\" @click=\"submit\" >Guardar</el-button>\r\n        </div>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\n    export default {\r\n        props: ['showDialog', 'lots', 'stock','recordId'],\r\n        data() {\r\n            return {\r\n                titleDialog: 'Series',\r\n                loading: false,\r\n                errors: {},\r\n                form: {},\r\n                states: ['Activo', 'Inactivo', 'Desactivado', 'Voz', 'M2m']\r\n\r\n            }\r\n        },\r\n        async created() {\r\n\r\n            // await this.$http.get(`/pos/payment_tables`)\r\n            //     .then(response => {\r\n            //         this.payment_method_types = response.data.payment_method_types\r\n            //         this.cards_brand = response.data.cards_brand\r\n            //         this.clickAddLot()\r\n            //     })\r\n        },\r\n        methods: {\r\n            async duplicateSerie(data, index)\r\n            {\r\n\r\n                let duplicates = await _.filter(this.lots, {'series':data})\r\n                if(duplicates.length > 1)\r\n                {\r\n                    this.lots[index].series = ''\r\n                }\r\n            },\r\n            create(){\r\n\r\n                if(!this.recordId){\r\n\r\n                    if(this.lots.length == 0){\r\n\r\n                        this.addMoreLots(this.stock)\r\n\r\n                    }else{\r\n\r\n                        let quantity = this.stock - this.lots.length\r\n                        if(quantity > 0){\r\n                            this.addMoreLots(quantity)\r\n                        }\r\n                        // else{\r\n                        //     this.deleteMoreLots(quantity)\r\n                        // }\r\n                    }\r\n\r\n                }\r\n            },\r\n            addMoreLots(number){\r\n\r\n                for (let i = 0; i < number; i++) {\r\n                    this.clickAddLot()\r\n                }\r\n\r\n            },\r\n            deleteMoreLots(number){\r\n\r\n                for (let i = 0; i < number; i++) {\r\n                    this.lots.pop();\r\n                    this.$emit('addRowLot', this.lots);\r\n                }\r\n\r\n            },\r\n            async validateLots(){\r\n\r\n                let error = 0\r\n\r\n                await this.lots.forEach(element => {\r\n                    if(element.series == null){\r\n                        error++\r\n                    }\r\n                });\r\n\r\n                if(error>0)\r\n                    return {success:false, message:'El campo serie es obligatorio'}\r\n\r\n\r\n                return {success:true}\r\n\r\n            },\r\n            async submit(){\r\n\r\n                let val_lots = await this.validateLots()\r\n                if(!val_lots.success)\r\n                    return this.$toast.error(val_lots.message);\r\n\r\n                await this.$emit('addRowLot', this.lots);\r\n                await this.$emit('update:showDialog', false)\r\n\r\n            },\r\n            clickAddLot() {\r\n\r\n                if(!this.recordId){\r\n                    if(this.lots.length >= this.stock)\r\n                        return this.$toast.error('La cantidad de registros es superior al stock o cantidad');\r\n                }\r\n\r\n\r\n                this.lots.push({\r\n                    id: null,\r\n                    item_id: null,\r\n                    series: null,\r\n                    date:  moment().format('YYYY-MM-DD'),\r\n                    state: 'Activo'\r\n\r\n                });\r\n\r\n                this.$emit('addRowLot', this.lots);\r\n            },\r\n\r\n            close() {\r\n                this.$emit('update:showDialog', false)\r\n                this.$emit('addRowLot', this.lots);\r\n            },\r\n            clickCancel(index) {\r\n                this.lots.splice(index, 1);\r\n               // item.deleted = true\r\n                this.$emit('addRowLot', this.lots);\r\n            },\r\n\r\n            async clickCancelSubmit() {\r\n                this.$emit('addRowLot', []);\r\n                await this.$emit('update:showDialog', false)\r\n            },\r\n            close() {\r\n                this.$emit('update:showDialog', false)\r\n            },\r\n        }\r\n    }\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/items/partials/lots.vue","<template>\r\n    <el-dialog\r\n        :title=\"titleDialog\"\r\n    